type NonSharedUint8Array = ReturnType<typeof Uint8Array.from>;

declare const VERSION = "__VERSION__";

type Encodings = 'utf8' | 'base64' | 'base64url' | 'hex';
type Encoder = {
    fromBytes: (u: Uint8Array) => string;
    toBytes: (s: string) => NonSharedUint8Array;
};
declare const encoding: Record<Encodings, Encoder>;

export { VERSION, encoding };
export type { Encoder, Encodings, NonSharedUint8Array };
